package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.CoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.PlanningsurenCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RegulManagerFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenChainFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.EndingRegulException;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.RegulException;
import be.schaubroeck.lpb.rkm.rekenmotor.results.ResultaatHandler;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManagerFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManagerImpl;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;

import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ACTOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BOEK_DATUM_INTERVALLEN_SET_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENMODUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_CHAIN_FACTORY_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_FEEDBACK_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.RKM_COREHR_CONFIG_MANAGER;

public class VormArtikelsRekenmotorService implements RekenmotorService {

    protected static final boolean SUCCES = false;

    @Autowired
    private ResultaatHandlerService resultaatHandlerService;
    @Autowired
    private PersoonsDataManagerFactory persoonsDataManagerFactory;
    @Autowired
    @Qualifier("cachedConstantService")
    private ConstantService constantService;

    @Override
    public RekenContext berekenLoon(
            Admin admin, int persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, RekenMotorStrategy strategy,
            Rekenmodus rekenModus, String actor, CoreHrConfiguratie coreHrConfiguratie) {
        return berekenLoon(admin, persoonId, opdrachtNrs, rekenTijd, strategy, rekenModus, actor, new RekenContext(), coreHrConfiguratie);
    }

    @Override
    public RekenContext berekenLoon(
            Admin admin, int persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, RekenMotorStrategy strategy,
            Rekenmodus rekenModus, String actor, RekenContext actionParams, CoreHrConfiguratie coreHrConfiguratie) {
        RekenChainFactory factory = strategy.getRekenChainFactory();
        ResultaatHandler handler = strategy.getResultaatHandler();
        RegulManagerFactory regulManagerFactory = strategy.getRegulManagerFactory();
        RegulManager regulManager = regulManagerFactory.getRegulManager();
        TimeTools timeTools = new TimeTools(admin, constantService);

        Integer fiscaalJaar = timeTools.bepaalFiscaalJaar(rekenTijd);

        List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties = coreHrConfiguratie.getRkmCoreHrConfiguraties();
        List<PlanningsurenCoreHrConfiguratie> planningsurenConfiguraties = coreHrConfiguratie.getPlanningsurenCoreHrConfiguraties();
        RkmCoreHrConfiguratieManager coreHrConfiguratieManager = new RkmCoreHrConfiguratieManagerImpl(rkmCoreHrConfiguraties, planningsurenConfiguraties);

        PersoonsDataManager dataManager =
                persoonsDataManagerFactory.create(admin, persoonId, opdrachtNrs, rekenTijd, fiscaalJaar, regulManager, rekenModus);
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        RekenFeedback feedback = new RekenFeedback();


        RekenContext mainContext = new RekenContext();
        mainContext.put(REKENTIJD_KEY, rekenTijd);
        mainContext.put(FISCAAL_JAAR_KEY, fiscaalJaar);
        mainContext.put(REGUL_MANAGER_KEY, regulManager);
        mainContext.put(REKEN_CHAIN_FACTORY_KEY, factory);
        mainContext.put(PERSOON_KEY, persoon);
        mainContext.put(REKENMODUS_KEY, rekenModus);
        mainContext.put(ACTOR_KEY, actor);
        mainContext.put(REKEN_FEEDBACK_KEY, feedback);
        mainContext.put(PERSOONSDATA_MANAGER_KEY, dataManager);
        mainContext.put(RKM_COREHR_CONFIG_MANAGER, coreHrConfiguratieManager);
        handler.cleanResultaten(admin, mainContext);

        Set<LocalDateInterval> boekDatumIntervallen = actionParams.getUnchecked(BOEK_DATUM_INTERVALLEN_SET_KEY);
        if (boekDatumIntervallen != null) {
            mainContext.put(BOEK_DATUM_INTERVALLEN_SET_KEY, boekDatumIntervallen);
        }

        try {
            resultaatHandlerService.verwerkResultaten(admin, handler, mainContext);
        } catch (RegulException regulException) {
            regulManager.handleRegulException(rekenTijd, persoon, regulException);
        } catch (EndingRegulException regulException) {
        }

        regulManager.handleReguls(rekenTijd, persoon);
        resultaatHandlerService.verwerkReguls(admin, handler, mainContext, SUCCES);
        TimeLogContext.getInstance().endTimeLogging();
        return mainContext;
    }
}
